import { useState } from 'react';
import API from '../services/api.js';

export default function RecommendCard() {
  const [query, setQuery] = useState('machine learning');  // Default query
  const [recommendations, setRecommendations] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleRecommend = async () => {
    setLoading(true);
    setError('');
    setRecommendations([]);
    try {
      const results = await API.post('/recommend', { query });
      setRecommendations(results.data.recommendations || []);
    } catch (err) {
      setError('Failed to fetch recommendations. Is backend running on port 8000?');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="feature-card-clean p-6 max-w-md mx-auto">
      <h3 className="text-xl font-bold mb-4">🔍 Recommendations</h3>
      
      <div className="space-y-3">
        <input
          type="text"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="Enter research topic..."
          className="w-full p-3 border border-gray-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500"
          disabled={loading}
        />
        
        <button
          onClick={handleRecommend}
          disabled={loading}
          className="w-full bg-blue-600 text-white py-3 px-6 rounded-xl hover:bg-blue-700 disabled:opacity-50 transition font-medium"
        >
          {loading ? 'Fetching...' : 'Get Recommendations'}
        </button>

        {error && (
          <p className="text-red-500 text-sm p-2 bg-red-50 rounded-lg">{error}</p>
        )}

        {recommendations.length > 0 && (
          <div className="mt-4 p-4 bg-green-50 rounded-xl max-h-48 overflow-y-auto">
            <p className="font-semibold mb-2">Top Recommendations:</p>
            <ul className="space-y-1 text-sm">
              {recommendations.map((title, idx) => (
                <li key={idx} className="text-gray-800">• {title}</li>
              ))}
            </ul>
          </div>
        )}
      </div>

      <p className="text-xs text-gray-500 mt-4">
        Discover similar papers instantly.
      </p>
    </div>
  );
}
